module up_counter(clk, reset, Q);
    input clk, reset;
    output reg [2:0] Q;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset)
            Q <= 3'b000;
        else
            Q <= Q + 1;
    end
endmodule
